import { isNameObject } from "../operations/generalTypes.js";
import { escapeValue } from "./escapeValue.js";
//#region src/utils/createTransformer.ts
function createTransformer(literal) {
	return (statement, mapping = {}) => Object.keys(mapping).reduce((str, param) => {
		const val = mapping?.[param];
		return str.replace(new RegExp(`{${param}}`, "g"), val === void 0 ? "" : typeof val === "string" || isNameObject(val) ? literal(val) : String(escapeValue(val)).replace(/\$/g, "$$$$"));
	}, statement);
}
//#endregion
export { createTransformer };
